import json
import pymysql
import os

# Database connection settings
rds_host = os.environ['RDS_HOST']
username = os.environ['RDS_USERNAME']
password = os.environ['RDS_PASSWORD']
database = os.environ['RDS_DATABASE']

def lambda_handler(event, context):
    # Extract search parameters from the event
    search_params = event.get('queryStringParameters', {})
    
    # Initialize SQL query and parameters
    sql_query = "SELECT * FROM products WHERE 1=1"
    sql_params = []
    
    # Dynamically build the SQL query based on provided parameters
    if 'name' in search_params:
        sql_query += " AND name LIKE %s"
        sql_params.append(f"%{search_params['name']}%")
    if 'category' in search_params:
        sql_query += " AND category = %s"
        sql_params.append(search_params['category'])
    if 'price_min' in search_params:
        sql_query += " AND price >= %s"
        sql_params.append(search_params['price_min'])
    if 'price_max' in search_params:
        sql_query += " AND price <= %s"
        sql_params.append(search_params['price_max'])

    # Connect to the database
    connection = pymysql.connect(host=rds_host, user=username, password=password, database=database)
    
    try:
        with connection.cursor() as cursor:
            cursor.execute(sql_query, sql_params)
            results = cursor.fetchall()
            return {
                'statusCode': 200,
                'body': json.dumps(results)
            }
    except Exception as e:
        return {
            'statusCode': 500,
            'body': json.dumps({'error': str(e)})
        }
    finally:
        connection.close()